// Codegen: transform the CLI's `command-manifest.json` (emitted by
// `curie schema`) into a TypeScript module that exports it `as const`, so its
// command names and flags carry *literal* types. `cliCommand()` derives its
// action-id union and per-action flag keys from those literals, which is what
// makes a renamed/removed command or flag break `pnpm typecheck` (issue #278).
//
// A plain `import x from "x.json"` widens every string to `string`, erasing the
// literals -- hence this `as const` re-emit. The output
// (src/generated/commandManifest.ts) is a COMMITTED generated file, so the UI
// Docker build (which has no `cli/` in its context) and `pnpm build` use it
// directly. Run `pnpm gen:manifest` after changing the CLI surface and commit
// the result; CI drift-checks it against cli/command-manifest.json.

import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const uiRoot = join(here, "..");
const source = join(uiRoot, "..", "..", "cli", "command-manifest.json");
const outDir = join(uiRoot, "src", "generated");
const outFile = join(outDir, "commandManifest.ts");

const raw = readFileSync(source, "utf8");
// Reparse + reserialize so the emitted literal is normalized and the codegen
// fails loudly if the source is not valid JSON.
const manifest = JSON.parse(raw);

const banner = `// @generated by scripts/gen-command-manifest.mjs from cli/command-manifest.json
// Do not edit by hand. Run \`pnpm gen:manifest\` (or any pre* script) to refresh.
/* eslint-disable */
`;

const body = `export const commandManifest = ${JSON.stringify(manifest, null, 2)} as const;\n`;

mkdirSync(outDir, { recursive: true });
writeFileSync(outFile, banner + body);
